import React from 'react';

const AdminPanel = ({ rooms, archive, dailyLogs, threshold, setThreshold }) => {
    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Панель управления</h2>

            <div className="admin-stats-grid">
                <div className="stat-card">
                    <span className="stat-value">{rooms.filter(r => r.status === 'checked').length}</span>
                    <span className="stat-label">Проверено</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{rooms.filter(r => r.status === 'dnd').length}</span>
                    <span className="stat-label">DND</span>
                </div>
            </div>

            <div className="admin-settings-section">
                <h3>📜 Логи действий за сегодня</h3>
                <div style={{maxHeight: '150px', overflowY: 'auto', fontSize: '12px'}}>
                    {dailyLogs.map((log, i) => (
                        <div key={i} style={{padding: '5px 0', borderBottom: '1px solid #eee'}}>
                            <b>{log.time}</b> — {log.staff} в номере {log.roomId}: {log.action}
                        </div>
                    ))}
                </div>
            </div>

            <div className="admin-settings-section">
                <h3>📂 Архив отчетов (после 00:00)</h3>
                {archive.length === 0 ? <p>Архив пуст</p> : archive.map((day, i) => (
                    <div key={i} className="archive-item">
                        <span>{day.date}</span> — Проверено: {day.stats.checked}
                    </div>
                ))}
            </div>

            <div className="admin-settings-section">
                <h3>⚙️ Уведомления о сроках (дней)</h3>
                <div className="threshold-buttons">
                    {[30, 60, 90, 180].map(d => (
                        <button
                            key={d}
                            className={`t-btn ${threshold === d ? 'active' : ''}`}
                            onClick={() => setThreshold(d)}
                        >
                            {d}д
                        </button>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default AdminPanel;
